// // This module multiplies the input by 2 for values between 8 and 15, divides by 2 for values between 0 and 7, and sets the output to 0 otherwise.
module top_module(
  input [3:0] in,
  output reg [3:0] out
);always @(*)
  begin
    if (in >= 0 && in <= 7) // Range 0 to 7
      out = in << 1;
    else if (in >= 8 && in <= 15) // Range 8 to 15
      out = in >> 1;
    else // Outside range 0 to 15
      out = 0;
  end

endmodule
